import React from "react";

export default function Forecast() {
  return (
    <div className="text-white p-6 text-center">
      <h2 className="text-3xl font-semibold mb-4">📅 Forecast</h2>
      <p>Multi-day forecast and weather trends will appear here.</p>
    </div>
  );
}
